const upd = $json;
let telegram_id, chat_id, text = '', callback_data = '', update_type;

if (upd.message) {
  update_type = 'message';
  telegram_id = String(upd.message.from.id);
  chat_id     = String(upd.message.chat.id);
  text        = (upd.message.text || '').trim();
} else if (upd.callback_query) {
  update_type   = 'callback';
  telegram_id   = String(upd.callback_query.from.id);
  chat_id       = String(upd.callback_query.message.chat.id);
  callback_data = (upd.callback_query.data || '').trim();
  text          = callback_data;
} else {
  return [];
}

return [{ json: { update_type, telegram_id, chat_id, text, callback_data } }];

const state   = $items("Get User & State")[0].json.current_state || '';
const role    = $items("Get User & State")[0].json.role || '';
const text    = $node["Normalize"].json.text || '';
const cb      = $node["Normalize"].json.callback_data || '';
const upd     = $node["Normalize"].json.update_type;

// If state exists and user typed text (not a command)
if (state && upd === 'message' && !text.startsWith('/')) {
  return [{ json: { route: 'state', state, role, text, cb } }];
}

// ADM_* dan STF_* commands selalu ke admin/staff flow, bypass state check
const cmd = text || cb;
if (cmd.startsWith('ADM_') || cmd.startsWith('STF_') || cmd.startsWith('CONFIRM_')) {
  return [{ json: { route: role === 'admin' ? 'admin' : 'staff', state, role, text, cb } }];
}

// Cancel shortcut
if (text === '/cancel' || cb === 'CANCEL') {
  return [{ json: { route: 'cancel', state, role, text, cb } }];
}

// Route by command/callback
return [{ json: { route: role === 'admin' ? 'admin' : 'staff', state, role, text, cb } }];

