const admins = $input.all();
const req = $items("SQL: Create Approval Request");
const item = req[0]?.json?.item_code || '-';
const qty  = req[0]?.json?.qty || 0;
const rid  = req[0]?.json?.request_id || 0;
const user = $items("Get User & State")[0]?.json?.name || '-';
const createdAt = req[0]?.json?.created_at || new Date().toISOString();

// helper untuk padding
function pad(str, width, align = 'left') {
  str = String(str);
  if (str.length >= width) return str.slice(0, width);
  const padLen = width - str.length;
  return align === 'right' ? ' '.repeat(padLen) + str : str + ' '.repeat(padLen);
}

// atur lebar kolom
const colWidths = {
  tgl: 14,
  user: 16,
  item: 18,
  qty: 4,
  rid: 8
};

// format tanggal singkat
function formatDate(iso) {
  const d = new Date(iso);
  return `${String(d.getDate()).padStart(2,'0')}/${String(d.getMonth()+1).padStart(2,'0')} ${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
}

const header = pad('Tgl', colWidths.tgl) + ' ' + pad('User', colWidths.user) + ' ' + pad('Item', colWidths.item) + ' ' + pad('Qty', colWidths.qty, 'right') + ' ' + pad('ReqID', colWidths.rid);
const separator = '-'.repeat(header.length);

const tgl = formatDate(createdAt);
const row = pad(tgl, colWidths.tgl) + ' ' + pad(user.substring(0, colWidths.user), colWidths.user) + ' ' + pad(item.substring(0, colWidths.item), colWidths.item) + ' ' + pad(String(qty), colWidths.qty, 'right') + ' ' + pad('#' + rid, colWidths.rid);

// bangun teks pesan dengan code block monospace
let bodyText = '🔔 *REQUEST APPROVAL BARU*\n\n';
bodyText += '```' + '\n';
bodyText += header + '\n';
bodyText += separator + '\n';
bodyText += row + '\n';
bodyText += '```' + '\n\n';
bodyText += '*Balas dengan:*\n';
bodyText += '`ADM_APPR_APPROVE_' + rid + '`' + '\n';
bodyText += '`ADM_APPR_REJECT_' + rid + '`';

return admins.map(a => ({ json: {
  chat_id: a.json.telegram_id,
  text: bodyText,
}}));

